// app/api/users/route.ts
import { NextRequest, NextResponse } from 'next/server';

export async function GET(req: NextRequest) {
  const { searchParams } = new URL(req.url);
  const page = parseInt(searchParams.get('page') ?? '1');
  const users = await db.select().from(usersTable).limit(20).offset((page - 1) * 20);
  return NextResponse.json({ users, page });
}

export async function POST(req: NextRequest) {
  const body = await req.json();
  if (!body.email) return NextResponse.json({ error: 'Email required' }, { status: 400 });
  const user = await db.insert(usersTable).values(body).returning();
  return NextResponse.json(user, { status: 201 });
}

// app/api/users/[id]/route.ts — dynamic route
export async function GET(_: NextRequest, { params }: { params: { id: string } }) {
  const user = await db.select().from(usersTable).where(eq(usersTable.id, params.id));
  if (!user.length) return NextResponse.json({ error: 'Not found' }, { status: 404 });
  return NextResponse.json(user[0]);
}

// middleware.ts
import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';

export function middleware(request: NextRequest) {
  const token = request.cookies.get('auth-token')?.value;
  const isAuthPage = request.nextUrl.pathname.startsWith('/login');
  const isProtected = request.nextUrl.pathname.startsWith('/dashboard');

  if (isProtected && !token) {
    return NextResponse.redirect(new URL('/login', request.url));
  }
  if (isAuthPage && token) {
    return NextResponse.redirect(new URL('/dashboard', request.url));
  }
  return NextResponse.next();
}

export const config = { matcher: ['/dashboard/:path*', '/login'] };

